<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048</title>
<style>
  :root {
    --bg: #1a1a1f;
    --panel: #26262e;
    --cell: #33333d;
    --text: #eee;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: var(--bg);
    color: var(--text);
    font-family: "Segoe UI", Arial, sans-serif;
  }
  h1 { margin: 0 0 12px; font-size: 40px; letter-spacing: 2px; }
  .hud {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 16px;
  }
  .scorebox {
    background: var(--panel);
    padding: 8px 18px;
    border-radius: 8px;
    text-align: center;
  }
  .scorebox .label { font-size: 11px; text-transform: uppercase; color: #9a9aa8; }
  #score { font-size: 24px; font-weight: bold; }
  #reset {
    background: #4a6cf7;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 12px 20px;
    font-size: 15px;
    font-weight: bold;
    cursor: pointer;
  }
  #reset:hover { background: #5d7bff; }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 90px);
    grid-template-rows: repeat(4, 90px);
    gap: 10px;
    background: var(--panel);
    padding: 10px;
    border-radius: 12px;
  }
  .tile {
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--cell);
    border-radius: 8px;
    font-size: 32px;
    font-weight: bold;
    color: var(--text);
  }
  .tile[data-v="2"]    { background: #3d4a5c; }
  .tile[data-v="4"]    { background: #40566e; }
  .tile[data-v="8"]    { background: #c47c3d; color: #fff; }
  .tile[data-v="16"]   { background: #d0672f; color: #fff; }
  .tile[data-v="32"]   { background: #de5533; color: #fff; }
  .tile[data-v="64"]   { background: #e6432a; color: #fff; }
  .tile[data-v="128"]  { background: #d9b23a; color: #222; font-size: 28px; }
  .tile[data-v="256"]  { background: #dcae2c; color: #222; font-size: 28px; }
  .tile[data-v="512"]  { background: #e0a91e; color: #222; font-size: 28px; }
  .tile[data-v="1024"] { background: #e3a510; color: #222; font-size: 24px; }
  .tile[data-v="2048"] { background: #f0c000; color: #222; font-size: 24px; }
  #status { margin-top: 14px; height: 22px; font-size: 16px; color: #ffb84d; }
</style>
</head>
<body>
  <h1>2048</h1>
  <div class="hud">
    <div class="scorebox">
      <div class="label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div id="status"></div>

<script>
(function () {
  var SIZE = 4;
  var grid = [];
  var currentScore = 0;
  var boardEl = document.getElementById('board');
  var scoreEl = document.getElementById('score');
  var statusEl = document.getElementById('status');

  function emptyGrid() {
    var g = [];
    for (var r = 0; r < SIZE; r++) {
      g.push([]);
      for (var c = 0; c < SIZE; c++) g[r].push(0);
    }
    return g;
  }

  function emptyCells() {
    var cells = [];
    for (var r = 0; r < SIZE; r++)
      for (var c = 0; c < SIZE; c++)
        if (grid[r][c] === 0) cells.push([r, c]);
    return cells;
  }

  function spawnTile() {
    var cells = emptyCells();
    if (cells.length === 0) return;
    var pick = cells[Math.floor(Math.random() * cells.length)];
    grid[pick[0]][pick[1]] = Math.random() < 0.9 ? 2 : 4;
  }

  // Slide + merge one row toward index 0; each tile merges at most once.
  function slideRow(row) {
    var tiles = row.filter(function (v) { return v !== 0; });
    var out = [];
    var gained = 0;
    for (var i = 0; i < tiles.length; i++) {
      if (i + 1 < tiles.length && tiles[i] === tiles[i + 1]) {
        out.push(tiles[i] * 2);
        gained += tiles[i] * 2;
        i++; // skip the merged partner
      } else {
        out.push(tiles[i]);
      }
    }
    while (out.length < SIZE) out.push(0);
    return { row: out, gained: gained };
  }

  function getLine(dir, i) {
    var line = [];
    for (var j = 0; j < SIZE; j++) {
      if (dir === 'left')  line.push(grid[i][j]);
      if (dir === 'right') line.push(grid[i][SIZE - 1 - j]);
      if (dir === 'up')    line.push(grid[j][i]);
      if (dir === 'down')  line.push(grid[SIZE - 1 - j][i]);
    }
    return line;
  }

  function setLine(dir, i, line) {
    for (var j = 0; j < SIZE; j++) {
      if (dir === 'left')  grid[i][j] = line[j];
      if (dir === 'right') grid[i][SIZE - 1 - j] = line[j];
      if (dir === 'up')    grid[j][i] = line[j];
      if (dir === 'down')  grid[SIZE - 1 - j][i] = line[j];
    }
  }

  function move(dir) {
    if (['left', 'right', 'up', 'down'].indexOf(dir) === -1) return false;
    var moved = false;
    var gained = 0;
    for (var i = 0; i < SIZE; i++) {
      var line = getLine(dir, i);
      var result = slideRow(line);
      gained += result.gained;
      for (var j = 0; j < SIZE; j++) {
        if (line[j] !== result.row[j]) moved = true;
      }
      setLine(dir, i, result.row);
    }
    if (moved) {
      currentScore += gained;
      spawnTile();
      render();
    }
    return moved;
  }

  function canMove() {
    if (emptyCells().length > 0) return true;
    for (var r = 0; r < SIZE; r++)
      for (var c = 0; c < SIZE; c++) {
        var v = grid[r][c];
        if (c + 1 < SIZE && grid[r][c + 1] === v) return true;
        if (r + 1 < SIZE && grid[r + 1][c] === v) return true;
      }
    return false;
  }

  function render() {
    boardEl.innerHTML = '';
    for (var r = 0; r < SIZE; r++) {
      for (var c = 0; c < SIZE; c++) {
        var cell = document.createElement('div');
        cell.className = 'tile';
        var v = grid[r][c];
        if (v !== 0) {
          cell.textContent = v;
          cell.setAttribute('data-v', v);
        }
        boardEl.appendChild(cell);
      }
    }
    scoreEl.textContent = currentScore;
    statusEl.textContent = canMove() ? '' : 'Game over — press New Game';
  }

  function reset() {
    grid = emptyGrid();
    currentScore = 0;
    spawnTile();
    spawnTile();
    render();
  }

  document.addEventListener('keydown', function (e) {
    var map = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down'
    };
    if (map[e.key]) {
      e.preventDefault();
      move(map[e.key]);
    }
  });

  document.getElementById('reset').addEventListener('click', reset);

  window.game = {
    size: SIZE,
    reset: reset,
    move: move,
    board: function () {
      return grid.map(function (row) { return row.slice(); });
    },
    setBoard: function (arr) {
      grid = arr.map(function (row) {
        return row.map(function (v) { return Number(v) || 0; });
      });
      render();
    },
    score: function () { return currentScore; }
  };

  reset();
})();
</script>
</body>
</html>
